INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (17, 1006051, '温馨提示', '1.特殊无捻工艺原因，初次使用时可能会有少许掉毛现象，用清水漂洗即可去除，非产品质量问题。2.由于水中含有钙、镁等矿物质，毛巾水洗之后会稍微变硬。定期在含碱/盐/醋的水中蒸煮、浸泡，可使毛巾再次柔软。3、毛圈无捻工艺，使其本身触感柔软纤长，适合干擦，不适合过水搓洗。', 7, NULL);
