INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (447, 1356007, '温馨提示', '1.内附小袋逗猫粉，可刺激猫咪习惯使用抓板。2.逗猫粉建议每次使用1g左右，最好不要用量过度。3.怀孕的猫咪，产后的猫咪，刚做完手术的猫咪。或者有其他疾病的猫咪请勿使用逗猫粉。4.逗猫粉本身无害，只是对不同猫咪有不同影响。5.由于本品的主要材质为瓦楞纸板，故请置于阴凉干燥处存放，防水防潮防火。', 6, NULL);
