INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (450, 1369012, '提示', '30天无忧退换货说明：产品、配件需保持完好，无磨损、污渍，包材、说明书、合格证齐全，未使用，不影响二次销售。', 3, NULL);
INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (451, 1389000, '温馨提示', '1、购买前请确认您家中水管口径，本产品仅适用于中国国内标准的4分口径水管。\n2、适配国内标准4分口径水管。\nTakagi、KAKUDAI、LIXIL（INAX）、TOTO等大部分淋浴设备的水管直接安装即可。\n3、本款花洒存在新旧款迭代，内部胶圈颜色有区别，新款为白色透明，与旧款除颜色无任何区别，请放心使用。', 1, NULL);
INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (452, 1389000, '产地', '韩国', 2, NULL);
