INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (456, 1389000, '滤芯替换时间', '一般情况下，3个月替换一次滤芯能够保持较好的净水效果。根据各地水质不同，可以自行调整更换周期。', 6, NULL);
INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (457, 1389000, '使用注意', '1、如果产品出现侧面漏水的现象，可以拧开花洒盖，查看内部花洒橡胶圈是否对齐拧紧，花洒出水板下的橡胶圈固定不齐可能会导致漏水，适当调整即可恢复正常\n2、部分水中杂质较多的地区，水中杂质可能会堵塞出水孔，拆下出水板适当冲洗掉后，即可疏通出水孔，水流将恢复平直', 7, NULL);
INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (458, 1389000, '售后说明', '产品质量问题终身质保，只换不修，可联系客服进行售后处理；由于净水商品属于消耗产品，滤芯一经拆封使用则无法二次销售。如非商品质量问题，滤芯拆封或已过水，一律无法满足7天无理由退换货政策，敬请谅解', 8, NULL);
