INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (482, 1418015, '主要参数', '1、内容物：此组合含16卷懒人抹布；\n2、重量：190g/卷\n3、面料：70-80%木浆+30-20%PP，50g/㎡', 1, NULL);
INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (483, 1418015, '使用贴士', '1、请勿将该商品长时间浸泡在液体中，以免长时间浸泡导致木浆脱落，产生碎屑，影响使用；\n2、请勿用沸水浸泡或清洁该商品，以免造成木浆与PP分层，产生碎屑，影响使用；\n3、该商品在不影响使用性能的前提下，可干湿使用，且可重复使用多次，但不具备耐磨性。', 2, NULL);
INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (484, 1418015, '垃圾分类提示', '外包装塑料膜、标贴、胶带、使用后的抹布：干垃圾/其他垃圾；\n纸质腰封、使用后剩余的纸筒：可回收垃圾\n（具体视当地垃圾分类实施细则为准）', 3, NULL);
