INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (548, 1435025, '注意事项', '1.请勿将猫砂放在猫粮附近，以防猫咪误食。\n2.猫咪排泄物内含有大量有害微生物及细菌，请尽量将猫咪进食盆远离猫砂盆。\n3.猫砂开口以后请尽快使用。因为猫砂具有良好的吸水性，所以未使用的猫砂请勿放在阴暗潮湿的环境中，以防止受潮后影响使用效果。\n4.清理出的猫砂结团，请放至封闭的袋子里，禁止儿童接触，为了您的身体健康，每次清理后，请务必洗手。', 8, NULL);
