INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (616, 1476005, '维修政策', '保修政策严选致力于提供令顾客满意的服务，对于【存在质量问题】的商品：\n七日内包退换\n十五日内包修理或换货\n一年内包修理\n\n退货时，必须将全新的产品、附件（包装内外盒、充电包、数据线、说明书、其余附赠品等）一并装载齐全后退回。', 11, NULL);
