INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (708, 1525018, '使用说明', '1、加厚材质，更耐磨；网孔设计，吸附更多尘屑；\n2、无纺布工艺，可一次性使用，也可清洗后重复使用2-4次，弃用时请勿丢弃于马桶，以免堵塞；\n3、干湿两用，干用-静电除尘；湿用-清洁除垢。\n4、地巾尺寸较大，适配于严选懒人拖把', 5, NULL);
