INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (759, 1554052, '购前须知', '1，请务必按照说明书或扫码视屏指导进行贴膜；2，全屏玻璃膜并不是覆盖到所有的屏幕范围，而是有往屏幕弧边延伸，使边缘触摸时手感提升，并能对屏幕边缘有一定程度的保护，同时能规避和部分手机壳配合导致顶膜\n3，产品边缘由于是弧边，厚度更薄，所以此处是产品最薄弱的位置，请注意避免磕碰，否则可能导致产品破裂，4，产品同我们的云感手机壳，头层牛皮手机壳搭配使用能有效的降低边缘破损的概率', 1, NULL);
INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (760, 1554052, '贴膜注意事项', '1，请务必在尽量无尘的环境中操作贴膜\n2，如果贴膜前手机带有手机壳，请将手机壳取下\n3，将手机垫在不易移动且干净的位置，关掉手机屏幕\n4，治具固定好清理好手机屏幕后，请再次检查屏幕面是否有灰尘掉落，确认无灰尘后迅速撕掉产品的保护板并贴上玻璃膜\n5，按压住玻璃膜中间位置，轻轻取下贴膜治具，用指甲辅助按压排气即可\n6，贴膜后若有灰尘进入，请按照说明书指引使用除尘贴去除灰尘', 2, NULL);
