INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (770, 1555000, '温馨提示2', '本品松紧带经过预缩处理，可以延长松紧带使用寿命，保持长期使用不过松。前几次使用会有稍紧的体感，建议头几次短时间适用，以达到头围的合适宽度。', 6, NULL);
INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (771, 1555000, '洗涤提示', '真丝产品，请低温轻柔手洗，用真丝专用洗涤剂或者沐浴露，晾干后可低温熨烫。', 7, NULL);
INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (772, 1569014, '警告！', '1，产品的AC插口不具备电压转换功能，电器的电压不适用该地区电压时，不得使用本产品进行转接\n2，产品AC插口最大支持的功率为：110v电器-880W；220V电器-1840W，请务必保证产品功率在此范围内', 1, NULL);
