INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (955, 1691024, '配料表', '粉饼：水、大米、食用淀粉。香菇肉丝菜汤包：鸡蛋、香菇、牛肉、竹笋、胡萝卜、香菜、食用盐、鸡精调味料、白砂糖、香辛料、食品添加剂（谷氨酸钠、瓜尔胶、柠檬酸、5\'-呈味核苷酸二钠、5\'-鸟苷酸二钠）。卤水包：水、牛骨、牛肉、食用植物油、食盐、豆豉、酿造酱油、白砂糖、白酒、罗汉果、味精、香辛料、食品添加剂（5\'-呈味核苷酸二钠）', 9, NULL);
