INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (1003, 3406025, '配料表', '加拿大三文鱼+完整扇贝柱\n原料组成：三文鱼60%、扇贝5%、水；添加剂组成：卡拉胶、硫酸软骨素、牛磺酸、维生素A、维生素E、硫酸铜、硫酸亚铁\n斗笠鸡胸肉+切块鸡肝\n原料组成：鸡胸肉60%、鸡肝5%、水；添加剂组成：卡拉胶、硫酸软骨素、牛磺酸、维生素E、维生素C、硫酸铜、硫酸亚铁\n印度洋金枪鱼+完整虾仁\n原料组成：金枪鱼60%、虾仁5%、水；添加剂组成：卡拉胶、硫酸软骨素、牛磺酸、维生素E、维生素B、维生素A、硫酸铜、硫酸亚铁', 5, NULL);
