INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (1238, 3533020, '注意事项', '产品连接充电器的接口是USB-C（Type-C接口），需要配合PD充电头才能给苹果手机或iPad进行PD快充；\n如需达到20W快充，需要另行购买支持PD20W的USB-C（Type-C接口）充电器；\n产品需要保持干燥,若出现弹窗或无法充电,请使用干布擦拭苹果端子头部分', 8, NULL);
INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (1239, 3533020, '充电故障排查步骤', '1，当产品充电异常时，请检查苹果端子金属部分是否有氧化或脏污，使用干净抹布擦拭清理一下，再测试是否OK\n2，更换一条数据线看是否能正常使用\n3，更换一个充电头看是否能正常使用\n若以上步骤排查完毕还无法正常使用，请联系在线客服处理', 9, NULL);
