INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (1251, 3815023, '7天无理由退货说明', '该产品自签收次日起，7日内可享受无理由退货，由于个人原因退回费用用户承担。\n以下情况不享受7天无理由退货：\n1.经检测，有明显人为损坏痕迹；\n2.退货产品序列号与出库序列号不符；\n3.未经授权的拆机维修；\n4.未按产品说明书使用导致产品质量问题；\n5.原包装不完整，配件不齐全；', 9, NULL);
