INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (1425, 3989454, '温馨提示', '1.鞋盒内置有小包干燥剂和防霉片，无毒，符合国家标准，请家长务必监督使其远离宝宝，避免误食；\n2.新鞋可能会存在一些气味，气味来自于鞋底等材质本身，气味无毒无害，置于阴凉通风处进行通风后气味可散去；\n3.此款大底采用EVA发泡工艺，大底柔软有弹性，鞋子产品属于手工作业，生产过程中难免会产生大底切口位置变形问题，所以左右脚基本无法控制到完全对称;', 4, NULL);
INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (1426, 3989748, '品牌属性', '网易严选推荐选品，本产品为游卡桌游品牌，由杭州游卡网络技术有限公司生产制造', 1, NULL);
INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (1427, 3989748, '游戏时长', '约30~60分钟', 2, NULL);
INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (1428, 3989748, '游戏人数', '2-10人', 3, NULL);
INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (1429, 3990189, '选购指南', '本机型采用创新无焊接工艺，让跑步机的外观精度达到了家电级别，结构上也更稳固，更耐用。独特的双立柱+气压杆折叠结构，实现了扶手高度可调和半自动全折叠。两极减震系统既能大幅减少膝盖的压力，也能大幅降低噪音和振动传导，让跑步机真正复合家用场景下可折叠、方便移动、舒适、静音的要求。', 1, NULL);
INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (1430, 3990189, '★拆箱注意★', '1、外包装侧面可拆卸摊平，抬起主机尾部将整机推出即可。\n2、展开跑步机前，请务必揭开立柱红色底部升降锁（见说明书），升起后再锁止，强行抬升立柱可能导致损坏。\n3、启动前需打开电源线插口旁开关，并将磁吸安全锁安装在跑步机上。', 2, NULL);
