INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (1466, 3990319, '注意事项', '1.UVC灯工作时，请勿打开饮水机上盖直视；\n2.建议一周彻底更换一次饮用水；\n3.请保持底座和除菌水箱底部干燥，严禁浸泡清洗；\n4.建议3天左右更换一次饮用水，并清洗水箱内部和滤芯；\n5.清洗水箱时，勿冲洗水箱底部，勿使水进入水箱底部；\n6.请保持智能底座、灭菌水箱的底部干燥，严禁浸泡清洗；\n7.静音水泵需每月清洗一次，防止污垢堵塞水路导致出水不畅等异常现象；\n8.水箱不耐高温，水箱内水温不能超过60°。', 10, NULL);
