INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (1611, 3994931, '使用温馨提示', '1、请勿撕破内芯，仅供外部使用。\n2、请勿在被褥中与其他取暖设备同时使用。\n3、使用过程中如觉得温度过高或颈部不适，请立即停止使用。\n4、儿童及对温度变化不太敏感的患者，请在使用时特别注意，孕妇忌用。\n5、请勿入口，不慎吞入时，请马上漱口并就医诊断。\n6、本产品为一次性用品，请勿重复使用。', 6, NULL);
