INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (1726, 3998106, '温馨提示', '1、网易严选出售的食品，除明确质量问题外均不接受退换货。\n2、请将产品保存于阴凉、通风、干燥处，开瓶后请尽快饮用。\n3、适度饮酒怡情，过度饮酒伤身。\n4、注意：饮酒后禁止驾驶机动车。\n5、本品不对未成年人出售。', 8, NULL);
