INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (1763, 4000278, '使用方法', '1.在干净的猫砂盆里铺5-7厘米厚度的猫砂。\n2.当猫咪排泄的时候，会迅速吸收并结团，用猫砂铲铲除。\n3.直接倒入马桶冲走。\n4.及时添加新猫砂，每月更新，保持5厘米的厚度。', 9, NULL);
INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (1764, 4000278, '注意事项', '1.如果猫咪误食少量的豆腐猫砂，对猫咪身体无害。\n2.猫砂开口之后请尽快使用，因为猫砂具有良好的吸水性，所以未使用的猫砂请勿放在阴暗潮湿的环境中，以防止受潮影响使用效果。', 10, NULL);
