INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (1908, 4017718, '温馨提示', '1.请勿与其它清洁产品混用，远离儿童和宠物，避免吸入喷雾。2.不能用于亚克力以及经过油蜡处理过的实木制品上面，油漆慎用。3.铝、塑料、油漆表面、黑色大理石材质慎用。4.油烟机表面含有金属涂层，请慎用', 6, NULL);
