INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (1913, 4018204, '温馨提示', '非质量问题退换货说明：产品、配件、说明书、包装应保持完好，产品未安装、未使用。\n因大件商品物流费用高昂，非质量问题的退货，用户需承担往返物流费用（金额视取货地点而定），若包装缺失需承担包装费用100元（请务必保留原包装30天以上）。', 5, NULL);
INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (1914, 4018204, '物流配送', '本产品为merach品牌，承诺为您送货上门/楼，您可放心购买。如您遇到物流不配合送货上门/楼情况，您可选择拒签或者反馈给以下联系电话:400-189-1969。我们会为您尽快解决问题。', 6, NULL);
INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (1915, 4018204, '退换货', '本品牌产品为大件产品，支持7天无理由退换货的，产品退回运费需要自理(具体可咨询品牌电话：400-189-1969），建议用户保留原包装纸箱一段时间，切保证产品的完整性，以便后续退换货需求。', 7, NULL);
INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (1916, 4018204, '物流', '该商品正常发货，但因疫情问题，时效性以物流公司为准。（除湖北省和西藏等管制地区除外）', 8, NULL);
INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (1917, 4018204, '使用教程', '椭圆机使用教程视频可参考以下链接，配合说明使用：\n腾讯https://v.qq.com/x/page/k304052epqk.html\n优酷https://v.youku.com/v_show/id_XNDQ4MDA1NzM1Ng==.html?', 9, NULL);
