INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (1922, 4018446, '退换货提示', '非质量问题退换货说明：产品、配件、说明书、包装应保持完好，产品未安装、未使用。\n因大件商品物流费用高昂，非质量问题的退货，用户需承担往返物流费用（金额视取货地点而定），若包装缺失需承担包装费用100元（请务必保留原包装30天以上）。', 5, NULL);
INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (1923, 4018446, '退换货提示2', '本品牌产品为大件产品，支持7天无理由退换货的，产品退回运费需要自理(具体可咨询品牌电话：400-189-1969），建议用户保留原包装纸箱一段时间，切保证产品的完整性，以便后续退换货需求。', 6, NULL);
INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (1924, 4018446, '安装提示', '该产品为主体免安装设计，产品主体无需安装，为了确保仪表盘以及扶手的安全性，该部分需要用户根据说明书进行操作安装，安装视频参考：1.https://mp.weixin.qq.com/s/xqlYHXFNFF2N8-COTdSYKA\n2.https://v.qq.com/x/page/h3074fexmrw.html\n3.https://v.youku.com/v_show/id_XNDU2NzY4NzE5Mg==', 7, NULL);
